import React from 'react';
import { useQuery } from '@tanstack/react-query';
import { dashboardAPI } from '../services/api';

export default function Dashboard() {
  const { data, isLoading } = useQuery({
    queryKey: ['dashboard'],
    queryFn: () => dashboardAPI.get().then(r => r.data.data)
  });

  if (isLoading) return <div style={{ padding: 40, textAlign: 'center', color: '#6B7280' }}>Loading dashboard…</div>;

  const stats = data?.stats || {};
  const cards = [
    { label: 'Total Students', value: stats.total_students || 0, icon: '🎓', c: '#7C3AED', bg: '#EDE9FE' },
    { label: 'Total Employees', value: stats.total_employees || 0, icon: '👥', c: '#059669', bg: '#D1FAE5' },
    { label: "Today's Attendance", value: `${stats.todayAttendancePercent || 0}%`, icon: '✅', c: '#D97706', bg: '#FEF3C7' },
    { label: "Today's Collection", value: `₹${(stats.todayCollection || 0).toLocaleString('en-IN')}`, icon: '💰', c: '#DC2626', bg: '#FEE2E2' },
  ];

  return (
    <div>
      <div style={{ marginBottom: 20 }}>
        <h1 style={{ fontSize: 20, fontWeight: 700 }}>Good morning, Principal 👋</h1>
        <p style={{ fontSize: 12, color: '#6B7280', marginTop: 3 }}>Academic Year 2025–26 · {new Date().toDateString()}</p>
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4,1fr)', gap: 14, marginBottom: 20 }}>
        {cards.map(c => (
          <div key={c.label} style={{ background: '#fff', border: '0.5px solid #E5E7EB', borderRadius: 14, padding: 16, cursor: 'pointer', transition: 'all .18s' }}>
            <div style={{ width: 36, height: 36, borderRadius: 9, background: c.bg, display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 18, marginBottom: 12 }}>{c.icon}</div>
            <div style={{ fontSize: 22, fontWeight: 700, color: c.c, lineHeight: 1, marginBottom: 4 }}>{c.value}</div>
            <div style={{ fontSize: 11, color: '#6B7280' }}>{c.label}</div>
          </div>
        ))}
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 16 }}>
        <div style={{ background: '#fff', border: '0.5px solid #E5E7EB', borderRadius: 14 }}>
          <div style={{ padding: '14px 16px', borderBottom: '0.5px solid #F3F4F6', fontWeight: 600, fontSize: 13 }}>📢 Recent Notices</div>
          <div style={{ padding: 16 }}>
            {(data?.notices || []).map(n => (
              <div key={n.id} style={{ padding: '8px 0', borderBottom: '0.5px solid #F3F4F6', fontSize: 12 }}>
                <div style={{ fontWeight: 600 }}>{n.title}</div>
                <div style={{ color: '#9CA3AF', fontSize: 11, marginTop: 2 }}>{n.posted_by} · {new Date(n.publish_date).toLocaleDateString('en-IN')}</div>
              </div>
            ))}
            {!data?.notices?.length && <div style={{ color: '#9CA3AF', textAlign: 'center', padding: 20 }}>No notices yet</div>}
          </div>
        </div>

        <div style={{ background: '#fff', border: '0.5px solid #E5E7EB', borderRadius: 14 }}>
          <div style={{ padding: '14px 16px', borderBottom: '0.5px solid #F3F4F6', fontWeight: 600, fontSize: 13 }}>🆕 Recent Admissions</div>
          <div style={{ overflowX: 'auto' }}>
            <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 12 }}>
              <thead><tr style={{ background: '#F9FAFB' }}>
                {['Student', 'Class', 'Date'].map(h => (
                  <th key={h} style={{ padding: '8px 12px', textAlign: 'left', color: '#6B7280', fontSize: 10, fontWeight: 600, textTransform: 'uppercase' }}>{h}</th>
                ))}
              </tr></thead>
              <tbody>
                {(data?.recentAdmissions || []).map(s => (
                  <tr key={s.id}>
                    <td style={{ padding: '9px 12px', fontWeight: 600 }}>{s.first_name} {s.last_name}</td>
                    <td style={{ padding: '9px 12px', color: '#6B7280' }}>{s.class_name} {s.section_name}</td>
                    <td style={{ padding: '9px 12px', color: '#9CA3AF' }}>{new Date(s.admission_date).toLocaleDateString('en-IN')}</td>
                  </tr>
                ))}
                {!data?.recentAdmissions?.length && (
                  <tr><td colSpan={3} style={{ padding: 20, textAlign: 'center', color: '#9CA3AF' }}>No recent admissions</td></tr>
                )}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </div>
  );
}
